订阅 `ag2602` 合约行情，并输出行情信息

```py {5-8,19}
class Demo(...):
    def on_start(self) -> None:
        super().on_start()

        self.sub_market_data(
            exchange="SHFE",
            instrument_id="ag2602"
        )

    def on_stop(self):
        super().on_stop()

        self.unsub_market_data(
            exchange="SHFE",
            instrument_id="ag2602"
        )

    def on_tick(self, tick: TickData) -> None:
        self.output(tick)
```

----

订阅多个合约行情，并输出行情信息

```py {4,9-13,25}
class Demo(...):
    def __init__(self):
        ...
        self.my_instruments = {"SHFE": "ag2602", "CZCE": "AP601"}

    def on_start(self) -> None:
        super().on_start()

        for exchange, instrument_id in self.my_instruments.items():
            self.sub_market_data(
                exchange=exchange,
                instrument_id=instrument_id
            )

    def on_stop(self):
        super().on_stop()

        for exchange, instrument_id in self.my_instruments.items():
            self.unsub_market_data(
                exchange=exchange,
                instrument_id=instrument_id
            )

    def on_tick(self, tick: TickData) -> None:
        self.output(tick)
```

自定义副图显示指标

定义 `sub_indicator_data`，然后传参给 `self.widget.recv_kline`

```py {2-9,15}
class Demo(...):
    @property
    def sub_indicator_data(self) -> dict[str, float]:
        """副图指标"""
        return {
            "K": ...,
            "D": ...,
            "J": ...,
        }

    def callback(self, kline: KLineData) -> None:
        """接受 K 线回调"""
        self.widget.recv_kline({
            "kline": ...,
            **self.sub_indicator_data
        })
```
